import { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { ToastContainer } from 'react-toastify';
//import { addExpenses } from '../../../backend/Controllers/ExpenseController';
import { APIUrl, handleError, handleSuccess } from '../utils';
import ExpenseDetails from './ExpenseDetails';
import ExpensesTable from './ExpensesTable';
import ExpenseTrackerForm from './ExpenseTrackerForm';

function Home() {
    const [loggedInUser, setLoggedInUser] = useState('');
    const [expenses, setExpenses] = useState([]);
    const [expenseAmt, setExpenseAmt] = useState(0);
    const [incomeAmt, setIncomeAmt] = useState(0);
    const navigate = useNavigate();

    useEffect(() => {
        setLoggedInUser(localStorage.getItem('loggedInUser'))
    }, [])

    useEffect(() => {
        const amounts = expenses.map((item) => item.amount);

        const income = amounts.filter(item => item > 0)
        .reduce((acc, item) => (acc += item),0 );

        const exp = amounts.filter(item => item < 0)
        .reduce((acc, item) => (acc += item),0 ) * -1;

        setIncomeAmt(income);
        setExpenseAmt(exp);

    }, [expenses]);

    const handleLogout = (e) => {
        localStorage.removeItem('token');
        localStorage.removeItem('loggedInUser');
        handleSuccess('User Loggedout');
        setTimeout(() => {
            navigate('/login');
        }, 1000)
    }

    useEffect(() => {
    const fetchExpenses = async () => {
        try {
            const url = `${APIUrl}/expenses`;
            const headers = {
                headers: {
                    'Authorization': localStorage.getItem('token')
                }
            }
            const response = await fetch(url, headers);
            if(response.status === 403){
                navigate('/login');
                return;
            }
            const result = await response.json();
            console.log(result.data);
            setExpenses(result.data);
        } catch (err) {
            handleError(err);
        }
    };

        fetchExpenses()
    }, [navigate]);

    useEffect(() => {
    const addExpenses = async (data) => {
        try {
            const url = `${APIUrl}/expenses`;
            const headers = {
                headers: {
                    'Authorization': localStorage.getItem('token'),
                    'Content-Type':'application/json'
                },
                method:'POST',
                body: JSON.stringify(data)
            }
            const response = await fetch(url, headers);
            if(response.status === 403){
                navigate('/login');
                return;
            }
            const result = await response.json();
            console.log(result.data);
            setExpenses(result.data);
            handleSuccess(result.message);
        } catch (err) {
            handleError(err);
        }
    };
 
    }, []);

    const handleDeleteExpense = async (expenseId) =>{
         try {
            const url = `${APIUrl}/expenses/${expenseId}`;
            const headers = {
                headers: {
                    'Authorization': localStorage.getItem('token'),
                    'Content-Type':'application/json'
                },
                method:'DELETE'
            }
            const response = await fetch(url, headers);
            if(response.status === 403){
                navigate('/login');
                return;
            }
            const result = await response.json();
            console.log(result.data);
            setExpenses(result.data);
            handleSuccess(result.message);
        } catch (err) {
            handleError(err);
        }
    }

    return (
        <div>
            <div className='user-section'>
                <h1>Welcome {loggedInUser}</h1>
                <button onClick={handleLogout}>Logout</button>
            </div>

            <ExpenseDetails incomeAmt={incomeAmt} expenseAmt={expenseAmt} />

            <ExpenseTrackerForm  addExpenses={addExpenses} />

            <ExpensesTable expenses={expenses} handleDeleteExpense={handleDeleteExpense} />
            
            <ToastContainer />
        </div>
    )
}

export default Home
